using UnityEngine;
using Climbing;
using UnityEditor;

public class FlyingInspector
{
    public static string Inspect()
    {
        GameObject pm = GameObject.Find("Player_New/PlayerModel");
        if (pm == null) return "Player_New/PlayerModel not found";

        Rigidbody rb = pm.GetComponent<Rigidbody>();
        CapsuleCollider col = pm.GetComponent<CapsuleCollider>();
        ThirdPersonController tpc = pm.GetComponent<ThirdPersonController>();
        MovementCharacterController mcc = pm.GetComponent<MovementCharacterController>();

        string report = $"--- Player Inspection ({pm.name}) ---\n";

        if (rb != null) {
            report += $"Rigidbody: Gravity={rb.useGravity}, Kinematic={rb.isKinematic}, Constraints={rb.constraints}\n";
        } else {
            report += "Rigidbody: MISSING\n";
        }

        if (col != null) {
            report += $"Collider: IsTrigger={col.isTrigger}, Center={col.center}, Height={col.height}, Radius={col.radius}\n";
        } else {
            report += "Collider: MISSING\n";
        }

        if (tpc != null) {
            report += $"ThirdPersonController: Grounded={tpc.isGrounded}, State={tpc.customState}\n";
        }

        // Check if transform is parented to something moving or if it's high up
        report += $"Position: {pm.transform.position}, LocalPosition: {pm.transform.localPosition}\n";
        report += $"Parent: {(pm.transform.parent != null ? pm.transform.parent.name : "None")}\n";

        return report;
    }
}
